func TestComponent_ToolExecutionWithAllowedList(t *testing.T) {
	config := teamtools.DefaultConfig()
	config.AllowedTools = []string{"graph_query", "file_read"}

	rawConfig, err := json.Marshal(config)
	if err != nil {
		t.Fatalf("Marshal config failed: %v", err)
	}

	deps := component.Dependencies{
		NATSClient: nil,
	}

	comp, err := teamtools.NewComponent(rawConfig, deps)
	if err != nil {
		t.Fatalf("NewComponent() failed: %v", err)
	}

	registrar, ok := comp.(interface {
		RegisterToolExecutor(executor teamtools.ToolExecutor) error
	})
	if !ok {
		t.Fatal("Component should implement RegisterToolExecutor method")
	}

	executor, ok := comp.(interface {
		Execute(ctx context.Context, call agentic.ToolCall) (agentic.ToolResult, error)
	})
	if !ok {
		t.Fatal("Component should implement Execute method")
	}

	// Register allowed tool
	allowedExecutor := &mockToolExecutor{
		name:          "graph_query",
		returnContent: "allowed result",
	}
	if err := registrar.RegisterToolExecutor(allowedExecutor); err != nil {
		t.Fatalf("RegisterToolExecutor() failed: %v", err)
	}

	// Register disallowed tool
	disallowedExecutor := &mockToolExecutor{
		name:          "file_delete",
		returnContent: "should not execute",
	}
	if err := registrar.RegisterToolExecutor(disallowedExecutor); err != nil {
		t.Fatalf("RegisterToolExecutor() failed: %v", err)
	}

	ctx := context.Background()

	// Execute allowed tool - should succeed
	allowedCall := agentic.ToolCall{
		ID:   "call-1",
		Name: "graph_query",
	}
	result, err := executor.Execute(ctx, allowedCall)
	if err != nil {
		t.Errorf("Execute() with allowed tool should succeed, got error: %v", err)
	}
	if result.Content != "allowed result" {
		t.Errorf("Result.Content = %s, want 'allowed result'", result.Content)
	}

	// Execute disallowed tool - should fail
	disallowedCall := agentic.ToolCall{
		ID:   "call-2",
		Name: "file_delete",
	}
	result, err = executor.Execute(ctx, disallowedCall)
	if err == nil {
		t.Error("Execute() with disallowed tool should return error")
	}
	if result.Error == "" {
		t.Error("Result.Error should not be empty for disallowed tool")
	}
}

